const raw = $input.item.json.text || $input.item.json.content || $input.item.json.message?.content || '';
const ctx = $('Prepare AI Context').item.json;
const senderPsid = ctx.senderPsid;
const messageText = ctx.messageText;
const messageType = ctx.messageType;
const productContext = ctx.productContext || '';
const categoryList = ctx.categoryList || '';

let parsed;
try {
  let jsonStr = raw.trim();
  if (jsonStr.includes('```')) jsonStr = jsonStr.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const firstBrace = jsonStr.indexOf('{');
  const lastBrace = jsonStr.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
  }
  parsed = JSON.parse(jsonStr);
} catch (e) {
  const cleanRaw = raw.replace(/```[\s\S]*?```/g, '').trim();
  let fallbackReply = '';
  const msgLower = (messageText || '').toLowerCase();

  if (msgLower.match(/^(hi|hello|hey|assalam)/)) {
    fallbackReply = 'Hi! \u0995\u09C0 \u0996\u09C1\u0981\u099C\u099B\u09C7\u09A8? ' + (categoryList ? categoryList.split(', ').slice(0,3).join(', ') + ' available \u0986\u099B\u09C7\u0964' : '\u0995\u09C0 item \u09A6\u09B0\u0995\u09BE\u09B0 \u09AC\u09B2\u09C1\u09A8\u0964');
  } else if (msgLower.match(/available|ki ache|item|product|dekhao|show/)) {
    fallbackReply = productContext ? 'Available items:\n' + productContext.split('\n').slice(0,4).join('\n') + '\nSize/colour \u09AC\u09B2\u09B2\u09C7 stock check \u0995\u09B0\u09BF\u0964' : '\u098F\u0996\u09A8 \u0995\u09CB\u09A8 specific item \u0996\u09C1\u0981\u099C\u099B\u09C7\u09A8?';
  } else if (msgLower.match(/order|nibo|buy|confirm/)) {
    fallbackReply = '\u0995\u09CB\u09A8 product\u099F\u09BE order \u0995\u09B0\u09AC\u09C7\u09A8? Name \u09AC\u09BE number \u09AC\u09B2\u09C1\u09A8\u0964';
  } else if (cleanRaw.length > 5 && cleanRaw.length < 400 && !cleanRaw.includes('{')) {
    fallbackReply = cleanRaw;
  } else {
    fallbackReply = '\u0986\u09AA\u09A8\u09BE\u09B0 message \u09AC\u09C1\u099D\u09A4\u09C7 \u09AA\u09BE\u09B0\u09B2\u09BE\u09AE\u0964 \u0995\u09C0 item \u0996\u09C1\u0981\u099C\u099B\u09C7\u09A8 \u09AC\u09B2\u09C1\u09A8, \u09B8\u09BE\u09B9\u09BE\u09AF\u09CD\u09AF \u0995\u09B0\u099B\u09BF\u0964';
  }

  parsed = { replyText: fallbackReply, intent: msgLower.match(/^(hi|hello|hey)/) ? 'greeting' : 'browse', confidence: 'low', aiUsed: true, needsHumanSupport: false, telegramAlertText: '', memoryUpdate: {}, selectedProductIds: [], lastShownProducts: [] };
}

if (messageType === 'voice_failed') {
  parsed.replyText = 'Voice clear \u09AC\u09C1\u099D\u09A4\u09C7 \u09AA\u09BE\u09B0\u09BF\u09A8\u09BF\u0964 Please text \u0995\u09B0\u09C7 \u09AC\u09B2\u09AC\u09C7\u09A8 \u0985\u09A5\u09AC\u09BE \u0986\u09AC\u09BE\u09B0 voice \u09A6\u09BF\u09A8\u0964';
  parsed.intent = 'voice_failed';
}

if (!parsed.replyText || parsed.replyText.trim().length === 0) {
  parsed.replyText = '\u0995\u09C0 item \u0996\u09C1\u0981\u099C\u099B\u09C7\u09A8 \u09AC\u09B2\u09C1\u09A8, \u09B8\u09BE\u09B9\u09BE\u09AF\u09CD\u09AF \u0995\u09B0\u099B\u09BF\u0964';
}
if (parsed.replyText.length > 600) parsed.replyText = parsed.replyText.substring(0, 597) + '...';

return [{ json: { senderPsid, messageText, replyText: parsed.replyText, intent: parsed.intent || 'unknown', confidence: parsed.confidence || 'medium', aiUsed: true, needsHumanSupport: parsed.needsHumanSupport || false, telegramAlertText: parsed.telegramAlertText || '', memoryUpdate: parsed.memoryUpdate || {}, selectedProductIds: parsed.selectedProductIds || [], lastShownProducts: parsed.lastShownProducts || [] } }];

const data = $input.item.json;
const senderPsid = data.senderPsid;
const memUpdate = data.memoryUpdate || {};
const existingMem = $('Prepare AI Context').item.json.memory || {};

const memoryRow = {
  Memory_ID: existingMem.Memory_ID || (senderPsid + '_mem'),
  Sender_PSID: String(senderPsid),
  Customer_Name: existingMem.Customer_Name || '',
  Language_Style: existingMem.Language_Style || 'banglish',
  Last_Intent: data.intent || existingMem.Last_Intent || '',
  Last_Product_ID: memUpdate.lastProductId || existingMem.Last_Product_ID || '',
  Last_Product_Name: memUpdate.lastProductName || existingMem.Last_Product_Name || '',
  Last_Product_List: (memUpdate.lastShownProducts || existingMem.Last_Product_List || '').toString(),
  Last_Category: memUpdate.lastCategory || existingMem.Last_Category || '',
  Last_Size: memUpdate.lastSize || existingMem.Last_Size || '',
  Last_Color: memUpdate.lastColor || existingMem.Last_Color || '',
  Last_Budget: memUpdate.lastBudget || existingMem.Last_Budget || '',
  Last_Occasion: memUpdate.lastOccasion || existingMem.Last_Occasion || '',
  Last_User_Message: (data.messageText || '').substring(0, 300),
  Last_Bot_Reply: (data.replyText || '').substring(0, 500),
  Last_Shown_Products_With_Numbers: (memUpdate.lastShownProducts || existingMem.Last_Shown_Products_With_Numbers || '').toString(),
  Short_Summary: (data.intent || '') + ': ' + (data.messageText || '').substring(0, 80),
  Updated_At: new Date().toISOString()
};

return [{ json: { ...data, memoryRow } }];
